// ======================================================
const mapaApoio = new Map();

for (const item of apoio) {
  const paciente = String(item.Paciente || "").trim();
  if (!paciente) continue;

  const chave = normalizarTexto(paciente);
  mapaApoio.set(chave, item);
}

const resultado = [];

// ======================================================
// COMPARA SOMENTE PACIENTES EXISTENTES NOS DOIS LADOS
// ======================================================
for (const itemWorklab of worklab) {
  const pacienteWorklab = String(itemWorklab.Paciente || "").trim();
  if (!pacienteWorklab) continue;

  const chavePaciente = normalizarTexto(pacienteWorklab);

  const itemApoio = mapaApoio.get(chavePaciente);

  if (!itemApoio) continue;

  const quantidadeExamesWorklab = numeroSeguro(itemWorklab.quantidadeExames);
  const quantidadeExamesApoio = numeroSeguro(itemApoio.quantidadeExames);

  const matchQuantidadeExames =
    quantidadeExamesWorklab === quantidadeExamesApoio;

  if (matchQuantidadeExames) continue;

  resultado.push({
    json: {
      Paciente: pacienteWorklab,
      pacienteNormalizado: chavePaciente,

      PacienteWorklab: pacienteWorklab,
      PacienteApoio: itemApoio.Paciente || "",

      existeNoWorklab: true,
      existeNoApoio: true,

      quantidadeExamesWorklab,
      quantidadeExamesApoio,
      diferencaQuantidade: quantidadeExamesWorklab - quantidadeExamesApoio,

      matchPaciente: true,
      matchQuantidadeExames: false,

      erro: true,
      tipoDivergencia: "QUANTIDADE_EXAMES_DIFERENTE",
      mensagem: "Paciente encontrado, mas a quantidade de exames está diferente",

      dadosWorklab: itemWorklab,
      dadosApoio: itemApoio
    }
  });
}

