// Exemplo:
// "JOSÉ HENRIQUE DA COSTA" -> "JOSE HENRIQUE DA COSTA"
// " Jessica  Carvalho " -> "JESSICA CARVALHO"
// ======================================================
function normalizarNome(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

